from __future__ import annotations

import random
import time
from fastapi import FastAPI
from fastapi.middleware.cors import CORSMiddleware

from triage4.core.models import CasualtyNode, CasualtySignature, GeoPose
from triage4.graph.casualty_graph import CasualtyGraph
from triage4.perception.body_regions import BodyRegionPolygonizer
from triage4.signatures.bleeding_signature import BleedingSignatureExtractor
from triage4.signatures.breathing_signature import BreathingSignatureExtractor
from triage4.triage_reasoning.rapid_triage import RapidTriageEngine

app = FastAPI(title="triage4 API", version="0.2.0")

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

graph = CasualtyGraph()
triage_engine = RapidTriageEngine()
polygonizer = BodyRegionPolygonizer()
breath_extractor = BreathingSignatureExtractor()
bleed_extractor = BleedingSignatureExtractor()


def _preset_rows():
    return [
        ("C1", "immediate", 18.0, 24.0),
        ("C2", "delayed", 36.0, 42.0),
        ("C3", "minimal", 61.0, 28.0),
        ("C4", "delayed", 74.0, 61.0),
        ("C5", "immediate", 48.0, 77.0),
    ]


def _breath_signal(priority: str) -> list[float]:
    if priority == "immediate":
        return [0.01, 0.02, 0.01, 0.02, 0.01, 0.02]
    if priority == "delayed":
        return [0.10, 0.12, 0.11, 0.13, 0.12, 0.14]
    return [0.23, 0.26, 0.25, 0.27, 0.26, 0.28]


def _bleed_inputs(priority: str) -> tuple[float, float, float]:
    if priority == "immediate":
        return 0.95, 0.50, 0.45
    if priority == "delayed":
        return 0.40, 0.20, 0.15
    return 0.06, 0.03, 0.02


def seed_demo_data() -> None:
    if graph.nodes:
        return

    now = time.time()

    for cid, priority_hint, x, y in _preset_rows():
        breathing = breath_extractor.extract(_breath_signal(priority_hint))
        vr, td, ph = _bleed_inputs(priority_hint)
        bleeding = bleed_extractor.extract(vr, td, ph)

        perfusion = 0.82 if priority_hint == "immediate" else 0.46 if priority_hint == "delayed" else 0.19
        body_regions = polygonizer.build_from_center(x, y)

        sig = CasualtySignature(
            breathing_curve=breathing["breathing_curve"],
            chest_motion_fd=breathing["chest_motion_fd"],
            perfusion_drop_score=perfusion,
            bleeding_visual_score=bleeding["bleeding_visual_score"],
            visibility_score=round(random.uniform(0.78, 1.0), 2),
            body_region_polygons=body_regions,
            raw_features={
                "respiration_proxy": breathing["respiration_proxy"],
                "breathing_quality": breathing["quality_score"],
                "bleeding_confidence": bleeding["confidence"],
            },
        )

        priority, conf, _ = triage_engine.infer_priority(sig)
        node = CasualtyNode(
            id=cid,
            location=GeoPose(x=x, y=y),
            platform_source="demo_uav",
            confidence=round(max(conf, 0.50), 2),
            status="assessed",
            signatures=sig,
            hypotheses=triage_engine.build_hypotheses(sig),
            triage_priority=priority,
            first_seen_ts=now,
            last_seen_ts=now,
        )
        graph.upsert(node)
        graph.link("demo_uav", "observed", cid)


@app.on_event("startup")
def on_startup() -> None:
    seed_demo_data()


@app.get("/health")
def health() -> dict:
    return {"ok": True, "nodes": len(graph.nodes)}


@app.get("/casualties")
def casualties() -> list[dict]:
    return [n.to_dict() for n in graph.all_nodes()]


@app.get("/casualties/{casualty_id}")
def casualty_detail(casualty_id: str) -> dict:
    return graph.nodes[casualty_id].to_dict()


@app.get("/graph")
def graph_json() -> dict:
    return graph.as_json()


@app.get("/map")
def map_json() -> dict:
    return {
        "platforms": [
            {"id": "demo_uav", "x": 50, "y": 8, "kind": "uav"},
            {"id": "medic_1", "x": 15, "y": 90, "kind": "medic"},
        ],
        "casualties": [
            {
                "id": n.id,
                "x": n.location.x,
                "y": n.location.y,
                "priority": n.triage_priority,
                "confidence": n.confidence,
            }
            for n in graph.all_nodes()
        ],
    }


@app.get("/replay")
def replay_json() -> dict:
    frames = []
    casualties = graph.all_nodes()

    for t in range(6):
        frames.append(
            {
                "t": t,
                "platforms": [
                    {"id": "demo_uav", "x": 15 + (t * 7), "y": 10 + (t * 5), "kind": "uav"},
                ],
                "casualties": [
                    {
                        "id": n.id,
                        "x": n.location.x,
                        "y": n.location.y,
                        "priority": n.triage_priority,
                    }
                    for n in casualties
                ],
            }
        )

    return {"frames": frames}
