import { useEffect, useState } from "react";
import MapPage from "./pages/MapPage";
import ReplayPage from "./pages/ReplayPage";

type Casualty = {
  id: string;
  triage_priority: string;
  confidence: number;
  platform_source: string;
  location: { x: number; y: number; z: number };
  hypotheses: { kind: string; score: number; explanation: string }[];
  signatures: {
    bleeding_visual_score: number;
    perfusion_drop_score: number;
    chest_motion_fd: number;
    body_region_polygons?: Record<string, [number, number][]>;
    raw_features?: Record<string, number>;
  };
};

function priorityColor(priority: string): string {
  if (priority === "immediate") return "#ff5c5c";
  if (priority === "delayed") return "#ffb84d";
  if (priority === "minimal") return "#63d471";
  return "#a0aec0";
}

type TabKey = "casualties" | "map" | "replay";

export default function App() {
  const [items, setItems] = useState<Casualty[]>([]);
  const [selected, setSelected] = useState<Casualty | null>(null);
  const [tab, setTab] = useState<TabKey>("casualties");
  const [mapData, setMapData] = useState<any>(null);
  const [replayData, setReplayData] = useState<any>(null);

  useEffect(() => {
    fetch("http://127.0.0.1:8000/casualties")
      .then((r) => r.json())
      .then((data: Casualty[]) => {
        setItems(data);
        if (data.length > 0) setSelected(data[0]);
      });

    fetch("http://127.0.0.1:8000/map")
      .then((r) => r.json())
      .then(setMapData);

    fetch("http://127.0.0.1:8000/replay")
      .then((r) => r.json())
      .then(setReplayData);
  }, []);

  return (
    <div style={{ display: "grid", gridTemplateColumns: "360px 1fr", minHeight: "100vh" }}>
      <aside style={{ borderRight: "1px solid #1e2a44", padding: 16 }}>
        <h2 style={{ marginTop: 0 }}>triage4</h2>
        <div style={{ opacity: 0.8, marginBottom: 16 }}>MVP dashboard</div>

        <div style={{ display: "flex", gap: 8, marginBottom: 16 }}>
          <button onClick={() => setTab("casualties")}>Casualties</button>
          <button onClick={() => setTab("map")}>Map</button>
          <button onClick={() => setTab("replay")}>Replay</button>
        </div>

        {items.map((item) => (
          <div
            key={item.id}
            onClick={() => {
              setSelected(item);
              setTab("casualties");
            }}
            style={{
              cursor: "pointer",
              marginBottom: 12,
              padding: 12,
              borderRadius: 10,
              border: `1px solid ${priorityColor(item.triage_priority)}`,
              background: selected?.id === item.id ? "#121a30" : "#0e1528"
            }}
          >
            <div style={{ fontWeight: 700 }}>{item.id}</div>
            <div style={{ color: priorityColor(item.triage_priority), textTransform: "uppercase" }}>
              {item.triage_priority}
            </div>
            <div style={{ fontSize: 12, opacity: 0.8 }}>
              confidence: {item.confidence}
            </div>
          </div>
        ))}
      </aside>

      <main style={{ padding: 20 }}>
        {tab === "map" && <MapPage data={mapData} />}
        {tab === "replay" && <ReplayPage data={replayData} />}

        {tab === "casualties" && selected && (
          <>
            <h1 style={{ marginTop: 0 }}>{selected.id}</h1>

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
              <section style={{ background: "#0e1528", padding: 16, borderRadius: 12 }}>
                <h3>Overview</h3>
                <div>
                  Priority:{" "}
                  <b style={{ color: priorityColor(selected.triage_priority) }}>
                    {selected.triage_priority}
                  </b>
                </div>
                <div>Confidence: {selected.confidence}</div>
                <div>Platform: {selected.platform_source}</div>
                <div>
                  Location: ({selected.location.x}, {selected.location.y}, {selected.location.z})
                </div>
              </section>

              <section style={{ background: "#0e1528", padding: 16, borderRadius: 12 }}>
                <h3>Signals</h3>
                <div>Bleeding score: {selected.signatures.bleeding_visual_score}</div>
                <div>Perfusion drop: {selected.signatures.perfusion_drop_score}</div>
                <div>Chest motion FD: {selected.signatures.chest_motion_fd}</div>
                <div>
                  Respiration proxy:{" "}
                  {selected.signatures.raw_features?.respiration_proxy ?? "—"}
                </div>
              </section>

              <section style={{ background: "#0e1528", padding: 16, borderRadius: 12 }}>
                <h3>Body Regions</h3>
                <div style={{ fontSize: 13, opacity: 0.9 }}>
                  {selected.signatures.body_region_polygons
                    ? Object.keys(selected.signatures.body_region_polygons).join(", ")
                    : "No polygons"}
                </div>
              </section>

              <section style={{ background: "#0e1528", padding: 16, borderRadius: 12 }}>
                <h3>Hypotheses</h3>
                {selected.hypotheses.length === 0 ? (
                  <div style={{ opacity: 0.7 }}>No active hypotheses</div>
                ) : (
                  selected.hypotheses.map((h, idx) => (
                    <div key={idx} style={{ marginBottom: 10, padding: 10, background: "#121a30", borderRadius: 8 }}>
                      <div>
                        <b>{h.kind}</b> — {h.score}
                      </div>
                      <div style={{ opacity: 0.8 }}>{h.explanation}</div>
                    </div>
                  ))
                )}
              </section>
            </div>
          </>
        )}

        {tab === "casualties" && !selected && <div>Loading…</div>}
      </main>
    </div>
  );
}
